"""Auto-generated gRPC stubs package.

Adds this directory to sys.path so that generated imports like
`from dhruva.v1 import auth_pb2` resolve correctly regardless of
where the package is installed.
"""
import pathlib
import sys

_here = str(pathlib.Path(__file__).parent)
if _here not in sys.path:
    sys.path.insert(0, _here)
